import fs from 'fs';
import path from 'path';

// Builds the "Cross-Disciplinary" graph: edges between faculty in DIFFERENT
// departments whose keywords match a known productive method<->domain pairing
// (data/domain_affinity.json, generated by pipeline/build_domain_affinity.py).
// Deliberately separate from build-edges.mjs's similarity graph — that one rewards
// topical closeness (which clusters by department); this one rewards complementarity.

const BASE_DIR = path.join(process.cwd(), '..');
const FACULTY_DIR = path.join(BASE_DIR, 'data', 'faculty');
const AFFINITY_FILE = path.join(BASE_DIR, 'data', 'domain_affinity.json');
const OUTPUT_FILE = path.join(BASE_DIR, 'data', 'cross_edges.json');

function getCanonical(k) {
  if (k && typeof k === 'object') return k.canonical || k.term || k.keyword || String(k);
  return String(k);
}

function normKey(s) {
  return String(s).trim().toLowerCase();
}

function main() {
  if (!fs.existsSync(AFFINITY_FILE)) {
    console.log(`No ${AFFINITY_FILE} found. Run pipeline/build_domain_affinity.py first.`);
    fs.writeFileSync(OUTPUT_FILE, '[]', 'utf8');
    return;
  }

  const affinity = JSON.parse(fs.readFileSync(AFFINITY_FILE, 'utf8'));
  // normalized-pair-key -> rationale, both directions
  const affinityMap = new Map();
  for (const { a, b, rationale } of affinity) {
    const na = normKey(a);
    const nb = normKey(b);
    affinityMap.set(`${na}|${nb}`, { a, b, rationale });
    affinityMap.set(`${nb}|${na}`, { a: b, b: a, rationale });
  }
  console.log(`Loaded ${affinity.length} affinity pairs.`);

  const files = fs.readdirSync(FACULTY_DIR).filter((f) => f.endsWith('.json') && f !== 'example.json');
  const faculty = files.map((f) => JSON.parse(fs.readFileSync(path.join(FACULTY_DIR, f), 'utf8')));

  const edges = [];
  for (let i = 0; i < faculty.length; i++) {
    for (let j = i + 1; j < faculty.length; j++) {
      const fac1 = faculty[i];
      const fac2 = faculty[j];

      // Cross-disciplinary only means something between different departments —
      // two people in the same department sharing a method<->domain pair is just
      // normal overlap, already covered by the similarity graph.
      if (!fac1.department || !fac2.department || fac1.department === fac2.department) continue;

      const kws1 = (fac1.extracted_keywords || []).map(getCanonical);
      const kws2 = (fac2.extracted_keywords || []).map(getCanonical);

      const matches = [];
      const seenPairs = new Set();
      for (const k1 of kws1) {
        for (const k2 of kws2) {
          const hit = affinityMap.get(`${normKey(k1)}|${normKey(k2)}`);
          if (hit) {
            const pairKey = [normKey(k1), normKey(k2)].sort().join('|');
            if (seenPairs.has(pairKey)) continue;
            seenPairs.add(pairKey);
            matches.push({ keyword_a: k1, keyword_b: k2, rationale: hit.rationale });
          }
        }
      }

      if (matches.length > 0) {
        edges.push({
          source: fac1.id,
          target: fac2.id,
          matches,
          weight: Math.min(matches.length / 3, 1.0),
        });
      }
    }
  }

  fs.writeFileSync(OUTPUT_FILE, JSON.stringify(edges, null, 2), 'utf8');
  console.log(`Generated ${edges.length} cross-disciplinary edges among ${faculty.length} faculty.`);
}

main();
